from txn_simulator import Workload
from workloads import WORKLOAD_1, WORKLOAD_2, WORKLOAD_3
import time
import random
from collections import defaultdict, deque

def get_best_schedule(workload: Workload, num_seqs: int) -> tuple[int, list[int]]:
    n = workload.num_txns

    # Group transactions by the first write key
    write_start_map = defaultdict(list)
    for i in range(n):
        txn = workload.txns[i]
        for op_type, key, pos, txn_len in txn:
            if op_type == 'w':
                write_start_map[key].append(i)
                break

    # Also track transactions that start with reads
    read_start_txns = []
    for i in range(n):
        txn = workload.txns[i]
        if not any(op_type == 'w' for op_type, _, _, _ in txn[:1]):
            read_start_txns.append(i)

    # Build adjacency list for dependency-like relationships
    # A transaction depends on another if it reads a key that another writes
    # and the read happens before any write of that key in the reading transaction
    dependents = defaultdict(set)
    writers_of_key = defaultdict(list)

    # First pass: collect writers for each key
    for i in range(n):
        txn = workload.txns[i]
        for op_type, key, pos, txn_len in txn:
            if op_type == 'w':
                writers_of_key[key].append(i)

    # Second pass: build dependencies based on read-after-write patterns
    for i in range(n):
        txn = workload.txns[i]
        keys_read_before_write = set()
        has_written = set()

        for op_type, key, pos, txn_len in txn:
            if op_type == 'r':
                if key not in has_written:
                    keys_read_before_write.add(key)
            else:  # 'w'
                has_written.add(key)

        # For each key read before any write in this transaction,
        # add dependencies to recent writers of that key
        for key in keys_read_before_write:
            if writers_of_key[key]:
                # Take the last writer before this transaction (by index)
                # This creates a partial order
                for writer in writers_of_key[key]:
                    if writer != i:
                        dependents[writer].add(i)

    # Schedule construction using topological-like ordering with conflict awareness
    scheduled = [False] * n
    schedule = []

    # Priority: transactions with no dependencies first
    available = deque()
    for i in range(n):
        # Check if i has no incoming dependencies
        has_incoming = False
        for j in range(n):
            if i != j and i in dependents[j]:
                has_incoming = True
                break
        if not has_incoming:
            available.append(i)

    # If no transactions are available, start with all
    if not available:
        available = deque(range(n))

    while len(schedule) < n:
        if not available:
            # Find any unscheduled transaction
            for i in range(n):
                if not scheduled[i]:
                    available.append(i)
                    break

        # Select next transaction using a simple heuristic
        # Prefer transactions that write to keys not recently written
        if available:
            # Track recently written keys
            recent_writes = set()
            if schedule:
                last_txn = schedule[-1]
                for op_type, key, pos, txn_len in workload.txns[last_txn]:
                    if op_type == 'w':
                        recent_writes.add(key)

            # Score each available transaction
            best_score = float('inf')
            best_txn = available[0]

            for txn_idx in available:
                txn = workload.txns[txn_idx]
                score = 0
                # Penalize transactions that read recently written keys
                for op_type, key, pos, txn_len in txn:
                    if op_type == 'r' and key in recent_writes:
                        score += 1
                # Prefer shorter transactions
                score += len(txn) * 0.1

                if score < best_score:
                    best_score = score
                    best_txn = txn_idx

            # Schedule the best transaction
            schedule.append(best_txn)
            scheduled[best_txn] = True

            # Remove from available
            available = deque([txn for txn in available if txn != best_txn])

            # Add newly available transactions (dependents of the scheduled one)
            for dep in dependents[best_txn]:
                if not scheduled[dep]:
                    # Check if all dependencies of dep are now scheduled
                    all_deps_scheduled = True
                    for j in range(n):
                        if dep in dependents[j] and not scheduled[j]:
                            all_deps_scheduled = False
                            break
                    if all_deps_scheduled:
                        available.append(dep)

    # Final refinement: try adjacent swaps in the schedule
    current_makespan = workload.get_opt_seq_cost(schedule)

    for i in range(len(schedule) - 1):
        # Try swapping adjacent transactions
        new_schedule = schedule.copy()
        new_schedule[i], new_schedule[i + 1] = new_schedule[i + 1], new_schedule[i]
        new_makespan = workload.get_opt_seq_cost(new_schedule)

        if new_makespan < current_makespan:
            schedule = new_schedule
            current_makespan = new_makespan

    return current_makespan, schedule

def get_random_costs() -> tuple[int, list[list[int]], float]:
    random.seed(42)
    start_time = time.time()

    workload1 = Workload(WORKLOAD_1)
    makespan1, schedule1 = get_best_schedule(workload1, 10)

    workload2 = Workload(WORKLOAD_2)
    makespan2, schedule2 = get_best_schedule(workload2, 10)

    workload3 = Workload(WORKLOAD_3)
    makespan3, schedule3 = get_best_schedule(workload3, 10)

    total_makespan = makespan1 + makespan2 + makespan3

    return total_makespan, [schedule1, schedule2, schedule3], time.time() - start_time

if __name__ == "__main__":
    total_makespan, schedules, execution_time = get_random_costs()
    print(f"Total Makespan: {total_makespan}")
    print(f"Execution Time: {execution_time:.4f} seconds")
